import {ethers, solidityPacked} from "ethers"
const deployer = "0x9B137463d4E7986D7f535f9B79e28b4EF1938E9b";
const salt = ethers.keccak256(solidityPacked(["uint256"], [BigInt(123456)]));
// const bytecode = ""
const bytecode ="";

const encodedArgs = ethers.AbiCoder.defaultAbiCoder().encode(["uint256"], [BigInt(123456)]);
const initCode = ethers.concat([bytecode, encodedArgs]);
const bytecodeHash = ethers.keccak256(initCode);

const address = ethers.concat([
  "0xff",
  deployer,
  salt,
  bytecodeHash
]);

const childAddress = ethers.getAddress(
  "0x" + ethers.keccak256(address).slice(-40)
);


console.log("Bytecode Hash:", bytecodeHash);
console.log("Child Contract Address:", childAddress);
console.log(encodedArgs)